    80→    pub fn load() -> Self {
    81→        if let Some(path) = Self::config_path() {
    82→            if path.exists() {
    83→                if let Ok(content) = fs::read_to_string(&path) {
    84→                    if let Ok(config) = serde_json::from_str(&content) {
    85→                        return config;
    86→                    }
    87→                }
    88→            }
    89→        }
    90→        Self::default()
    91→    }
