    93→    pub fn save(&self) -> Result<(), String> {
    94→        let path = Self::config_path().ok_or("Could not determine config path")?;
    95→
    96→        println!("[Config] Saving to: {:?}", path);
    97→
    98→        if let Some(parent) = path.parent() {
    99→            fs::create_dir_all(parent).map_err(|e| {
   100→                let err = format!("Failed to create config dir: {}", e);
   101→                println!("[Config] {}", err);
   102→                err
   103→            })?;
   104→        }
   105→
   106→        let content = serde_json::to_string_pretty(self).map_err(|e| e.to_string())?;
   107→        fs::write(&path, content).map_err(|e| {
   108→            let err = format!("Failed to write config: {}", e);
   109→            println!("[Config] {}", err);
   110→            err
   111→        })?;
   112→
   113→        println!("[Config] Saved successfully");
   114→        Ok(())
   115→    }
   116→}
